const calendar = $input.first().json;
const now = new Date();
const argDate = new Date(now.getTime() - 3 * 60 * 60 * 1000);
const argDD = String(argDate.getUTCDate()).padStart(2, '0');
const argMM = String(argDate.getUTCMonth() + 1).padStart(2, '0');
const argYYYY = argDate.getUTCFullYear();
const todayStr = `${argDD}/${argMM}/${argYYYY}`;

const todayEntries = calendar.calendario.filter(e => e.fecha === todayStr && e.tipo === 'pieza');

if (todayEntries.length === 0) {
  return [{ json: { skip: true, message: `No hay piezas para hoy (${todayStr})`, date: todayStr } }];
}

const entry = todayEntries[0];
return [{ json: { skip: false, date: todayStr, ...entry } }];

const allItems = $input.all();
const pieces = allItems.map(item => item.json);

const entry = $('Find Today Piece').first().json;
const piece = pieces.find(p => p && p.id === entry.id);

// Evaluate dryRun — fail closed
let isDryRun = true;
try {
  const raw = $vars.dryRun;
  const normalized = String(raw ?? 'true').toLowerCase().trim();
  isDryRun = normalized !== 'false';
} catch (e) {
  isDryRun = true;
}

// Error case: piece not found
if (!piece) {
  return [{ json: {
    action: 'error',
    pieceId: entry.id,
    message: 'Piece not found: ' + entry.id
  } }];
}

// Anti-duplicado
const staticData = $getWorkflowStaticData('global');
const publishedToday = staticData.lastPublished || '';
const todayStr = entry.date;

if (publishedToday === piece.id + '_' + todayStr) {
  return [{ json: {
    action: 'duplicate',
    pieceId: piece.id,
    date: todayStr,
    headline: piece.headline,
    message: 'Pieza ya publicada hoy. Skip.'
  } }];
}

// Build image URL
const num = piece.id.replace('piece-', '');
const parts = piece.date.split('/');
const d = parts[0], m = parts[1], y = parts[2];
const dateStr = y + '-' + m + '-' + d;
const verticalSlug = piece.vertical.toLowerCase().replace(/\u00ed/g, 'i');
const manifestId = 'sm-' + dateStr + '-ig-feed-' + verticalSlug + '-' + num;
const pngName = num + '-' + d + '-' + m + '-' + y + '-' + verticalSlug + '.png';
const imageUrl = 'https://social-assets.espacionautico.com.ar/staging/' + y + '/' + m + '/' + manifestId + '/' + pngName;

// Decide action: publish or dryrun
const action = isDryRun ? 'dryrun' : 'publish';

return [{ json: {
  action: action,
  pieceId: piece.id,
  date: piece.date,
  vertical: piece.vertical,
  headline: piece.headline,
  captionIg: piece.captionIg,
  captionFb: piece.captionFb,
  imageUrl: imageUrl,
  manifestId: manifestId,
  igUserId: '17841443139761422',
  pageId: '1064806400040502'
} }];

const piece = $('Prepare Publish Data').first().json;
const igResult = $('IG Publish').first().json;
const fbResult = $('FB Publish').first().json;

const igId = igResult.id || 'ERROR';
const fbId = fbResult.id || 'ERROR';

const igUrl = 'https://www.instagram.com/espacionauticobsas/';
const fbUrl = 'https://www.facebook.com/' + fbId;

const ok = igId !== 'ERROR' && fbId !== 'ERROR';

// Record anti-duplicate
const staticData = $getWorkflowStaticData('global');
staticData.lastPublished = piece.pieceId + '_' + piece.date;

const subject = ok
  ? 'ENBA Redes: ' + piece.pieceId + ' publicado - ' + piece.headline
  : 'ENBA Redes ERROR: ' + piece.pieceId + ' publicacion parcial';

const body = 'PUBLICACION REDES - ENBA\n'
  + '========================\n\n'
  + 'Pieza: ' + piece.pieceId + '\n'
  + 'Fecha: ' + piece.date + '\n'
  + 'Vertical: ' + piece.vertical + '\n'
  + 'Headline: ' + piece.headline + '\n\n'
  + 'Instagram: ' + (igId !== 'ERROR' ? 'PUBLICADO' : 'FALLO') + '\n'
  + '  Post ID: ' + igId + '\n'
  + '  Ver en vivo: ' + igUrl + '\n\n'
  + 'Facebook: ' + (fbId !== 'ERROR' ? 'PUBLICADO' : 'FALLO') + '\n'
  + '  Post ID: ' + fbId + '\n'
  + '  Ver en vivo: ' + fbUrl + '\n\n'
  + 'Timestamp: ' + new Date().toISOString();

return [{ json: { subject, body, igId, fbId, pieceId: piece.pieceId } }];

const data = $('Find Today Piece').first().json;

const subject = '[INFO] ENBA Redes: sin pieza programada para hoy';

const body = 'SIN PIEZA PROGRAMADA\n'
  + '====================\n\n'
  + 'No hay pieza tipo "pieza" en el calendario para hoy (' + data.date + ').\n'
  + 'El workflow terminó sin publicar.\n\n'
  + 'Timestamp: ' + new Date().toISOString();

return [{ json: { subject, body } }];

const data = $('Prepare Publish Data').first().json;

const subject = '[SKIP] ENBA Redes: ' + data.pieceId + ' ya publicada hoy';

const body = 'ANTI-DUPLICADO ACTIVADO\n'
  + '========================\n\n'
  + 'La pieza ' + data.pieceId + ' ya fue publicada hoy.\n'
  + 'El workflow no volvió a publicar.\n\n'
  + 'Timestamp: ' + new Date().toISOString();

return [{ json: { subject, body } }];

const piece = $('Prepare Publish Data').first().json;

const subject = '[ERROR CRITICO] ENBA Redes: IG falló - ' + piece.pieceId;

const body = 'ERROR EN PUBLICACION IG\n'
  + '========================\n\n'
  + 'La publicación en Instagram FALLÓ.\n'
  + 'NO se intentó publicar en Facebook.\n'
  + 'NO se publicó nada.\n\n'
  + 'Pieza: ' + piece.pieceId + '\n'
  + 'Fecha: ' + piece.date + '\n'
  + 'Headline: ' + piece.headline + '\n\n'
  + 'ACCIÓN REQUERIDA: revisar error en n8n y reintentar.\n\n'
  + 'Timestamp: ' + new Date().toISOString();

return [{ json: { subject, body } }];

const data = $('Prepare Publish Data').first().json;

const subject = '[ERROR] ENBA Redes: acción desconocida - ' + (data.pieceId || 'sin pieza');
const body = 'ERROR EN WORKFLOW\n'
  + '=================\n\n'
  + 'El workflow llegó a un estado imprevisto.\n'
  + 'Acción recibida: ' + (data.action || 'undefined') + '\n'
  + 'Mensaje: ' + (data.message || 'sin mensaje') + '\n'
  + 'Pieza: ' + (data.pieceId || 'desconocida') + '\n\n'
  + 'ACCIÓN REQUERIDA: revisar ejecución en n8n.\n\n'
  + 'Timestamp: ' + new Date().toISOString();

return [{ json: { subject, body } }];
